        return {"pass": False, "score": 0.0, "feedback": "external_services_path not provided"}
    p = Path(external_services_path) / "slack_data.json"
    if not p.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    data = json.loads(p.read_text())
    users = data.get("users", {})

    def resolve(text):
        def rep(m):
            u = users.get(m.group(1), {})
            return f"{u.get('name','')} {u.get('real_name','')}"
        return re.sub(r'<@(U\w+)>', rep, text).lower()

    channel_id = next((cid for cid, c in data.get("channels", {}).items()
                       if c.get("name", "").lower() == "acct-chargebacks"), None)
    if not channel_id:
        return {"pass": False, "score": 0.0, "feedback": "Channel #acct-chargebacks not found"}

    _offset = INITIAL_MSG_COUNTS.get(
        next((c.get("name") for c in data.get("channels", {}).values()
               if c.get("id") == channel_id), ""), 0)
    new_msgs = data.get("messages", {}).get(channel_id, [])[_offset:]

    # PASS: must reference D. Watts, $480, Deal 4451, and CB-2608
    for msg in new_msgs:
        t = resolve(msg.get("text", ""))
        n = t.replace(",", "").replace("$", "")
        if ("watts" in t or "d. watts" in t) and re.search(r'(?<!\d)480(?!\d)', n) and "4451" in t and ("cb-2608" in t or "2608" in t):
            return {"pass": True, "score": 1.0,
                    "feedback": f"Found P23 commission offset notification in #acct-chargebacks: {t[:200]}"}

    # Diagnostic: closest partial match
    for msg in new_msgs:
        t = resolve(msg.get("text", ""))
        n = t.replace(",", "").replace("$", "")
        if any(k in t for k in ("watts", "480", "4451", "offset", "commission")):
            missing = [f for f, ok in [
                ("D. Watts", "watts" in t),
                ("$480", bool(re.search(r'(?<!\d)480(?!\d)', n))),
                ("Deal 4451", "4451" in t),
                ("CB-2608", ("cb-2608" in t or "2608" in t)),
            ] if not ok]
            return {"pass": False, "score": 0.0,
                    "feedback": f"Found offset-related message in #acct-chargebacks but missing fields: {missing}. Text: {t[:200]}"}

    previews = [resolve(m.get("text", ""))[:120] for m in new_msgs[:3]]
    return {"pass": False, "score": 0.0,
            "feedback": (f"No P23 commission offset notification in #acct-chargebacks. "
                         f"Expected: D. Watts/$480/Deal 4451/CB-2608. "
                         f"New messages ({len(new_msgs)}): {previews}")}

